import { Router } from 'express';
import { ClientController } from '../controllers/clients.controller.js';
const clientRouter = Router();
const controller = new ClientController();
clientRouter.post('/', controller.create.bind(controller));
clientRouter.get('/', controller.findAll.bind(controller));
clientRouter.get('/:id', controller.findById.bind(controller));
clientRouter.put('/:id', controller.update.bind(controller));
clientRouter.delete('/:id', controller.delete.bind(controller));
export { clientRouter };
